xpath.script:
(function () {
  function fillClubType() {
    var el = document.getElementById('club_type');
    if (!el || el.getAttribute('data-filled') === '1') return;
    if (!(window.odoo && odoo.jsonRpc)) return;

    odoo.jsonRpc('/signup/club_type_selection', 'call', {})
      .then(function (rows) {
        if (!rows || !rows.length) return;
        rows.forEach(function (r) {
          var opt = document.createElement('option');
          opt.value = r.value;
          opt.appendChild(document.createTextNode(r.label));
          el.appendChild(opt);
        });
        el.setAttribute('data-filled', '1');
      })
      .catch(function () {
        // keep silent on login page
      });
  }

  document.addEventListener('DOMContentLoaded', fillClubType);
  // safety fill in case of slow assets
  setTimeout(fillClubType, 300);
})();
